import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreEmptyLines() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withIgnoreEmptyLines();

        assertNotNull(result, "Resulting CSVFormat should not be null");
        assertTrue(result.getIgnoreEmptyLines(), "IgnoreEmptyLines should be true after calling withIgnoreEmptyLines()");
        // original format should remain unchanged (immutable)
        assertFalse(format.getIgnoreEmptyLines(), "Original CSVFormat's ignoreEmptyLines should remain false");
    }
}
